class Solution:
    def largestPalindrome(self, n: int, k: int) -> str:
        upper = 10**n - 1
        lower = 10**(n-1)
        for i in range(upper, lower-1, -1):
            if str(i) == str(i)[::-1] and i % k == 0:
                return str(i)
